const dataOntem = ymdInTZ(ontemSP);

// define data alvo
const datasDisponiveis = [...new Set(pedidosOut.map(p => p.data))].filter(Boolean).sort();
let dataAlvo = dataOntem;
let usouDataMaisRecente = false;

let pedidosDia = pedidosOut.filter(p => p.data === dataAlvo);

// se não há pedidos no "ontem", usa a última data disponível
if (pedidosDia.length === 0 && datasDisponiveis.length > 0) {
  dataAlvo = datasDisponiveis[datasDisponiveis.length - 1];
  pedidosDia = pedidosOut.filter(p => p.data === dataAlvo);
  usouDataMaisRecente = true;
}

// métricas do dia
const faturamentoTotal = to2(pedidosDia.reduce((a, p) => a + p.totalPedido, 0));
const totalPedidos = pedidosDia.length;
const totalItens = pedidosDia.reduce((a, p) => a + p.qtdItens, 0);
const clientesUnicos = new Set(pedidosDia.map(p => p.nomeCliente || 'SEM NOME')).size;
const ticketMedio = totalPedidos ? to2(faturamentoTotal / totalPedidos) : 0;

// por vendedor (dia)
const porVendValor = {};
const porVendQtd = {};
for (const p of pedidosDia) {
  const vend = p.vendedor || 'SEM VENDEDOR';
  acum(porVendValor, vend, p.totalPedido);
  acum(porVendQtd, vend, 1);
}
const porVendedor = Object.keys(porVendValor).map(v => ({
  vendedor: v,
  pedidos: porVendQtd[v] || 0,
  total: to2(porVendValor[v] || 0),
  ticketMedio: porVendQtd[v] ? to2(porVendValor[v] / porVendQtd[v]) : 0
})).sort((a, b) => b.total - a.total);

// por dia — só a data analisada
const porDia = [{ data: dataAlvo, total: faturamentoTotal }];

// top clientes do dia
const clientesDict = {};
for (const p of pedidosDia) acum(clientesDict, p.nomeCliente || 'SEM NOME', p.totalPedido);
const topClientes = topN(clientesDict, 10, 'valor');

// top produtos do dia
const prodDict = {};
for (const p of pedidosDia) {
  for (const it of (p.produtos || [])) {
    const nome = it.produto || 'SEM PRODUTO';
    if (!prodDict[nome]) prodDict[nome] = { qtd: 0, valor: 0 };
    prodDict[nome].qtd += Number(it.quantidade || 0);
    prodDict[nome].valor += Number(it.preco || 0);
  }
}
const topProdutosQtd = topN(prodDict, 10, 'qtd');
const topProdutosValor = topN(prodDict, 10, 'valor');

// pedidos atípicos no dia: > 2 x ticket médio do dia
const pedidosAtipicos = ticketMedio > 0
  ? pedidosDia.filter(p => p.totalPedido > 2 * ticketMedio).map(p => p.numeroDocumento)
  : [];

const resumo = {
  numeroLoja,
  dataAlvo,
  usouDataMaisRecente,
  faturamentoTotal,
  totalPedidos,
  totalItens,
  clientesUnicos,
  ticketMedio,
  pedidosAtipicos
};

return [
