function limparTexto(s) {
  return String(s || "").replace(/\s+/g, " ").replace(/[;]+$/g, "").trim();
}
function splitEmails(s) {
  if (!s) return [];
  return String(s).split(/[;,]/).map(x => x.trim()).filter(Boolean);
}
function limparEmail(s) {
  const e = String(s || "").trim().replace(/[;]+$/g, "");
  if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(e)) return "";
  return e.toLowerCase();
}
function normalizePhone(s) {
  if (!s) return "";
  const digits = String(s).replace(/\D/g, "");
  if (digits.length === 10 || digits.length === 11) return digits;
  if (digits.length === 12 || digits.length === 13) {
    const semDDI = digits.replace(/^55/, "");
    if (semDDI.length === 10 || semDDI.length === 11) return semDDI;
  }
  return "";
}
function dedup(arr) { return Array.from(new Set(arr.filter(Boolean))); }
function normalizaData(s) {
  if (!s) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const n = Number(s);
  if (Number.isFinite(n)) {
    const d = new Date(n);
    if (!isNaN(d.getTime())) return d.toISOString().slice(0, 10);
  }
  return null;
}
function toNumber(v) { const n = Number(v); return Number.isFinite(n) ? n : null; }

function formataCEP(s) {
  const d = String(s || "").replace(/\D/g, "");
  if (d.length === 8) return d.slice(0,5) + "-" + d.slice(5);
  return d || null;
}

function montarEnderecoCliente(pedido) {
  const c = pedido?.cliente;
  if (c) {
    const cidadeUF = c?.cidade ? [c.cidade.nomeCidade, c.cidade.siglaEstado].filter(Boolean).join(" ") : "";
    const partes = [
      limparTexto([c.endereco, c.numero].filter(Boolean).join(", ")),
      limparTexto(c.complemento),
      limparTexto(c.bairro),
      limparTexto(cidadeUF),
      formataCEP(c.cep),
    ].filter(Boolean);
    const joined = partes.join(", ").replace(/\s+,/g, ",").trim();
    if (joined) return joined;
  }
  return null;
}

function extrairContatoSimples(pedido) {
  const fones = dedup([
    normalizePhone(pedido?.cliente?.telefone1),
    normalizePhone(pedido?.cliente?.telefone2),
    normalizePhone(pedido?.telefoneConsumidor),
    normalizePhone(pedido?.cliente?.telefoneCelular),
    normalizePhone(pedido?.enderecoEntrega?.telefone),
  ]);
  const emails = dedup([
    ...splitEmails(pedido?.cliente?.email || ""),
    ...splitEmails(pedido?.cliente?.emailNfe || ""),
    ...splitEmails(pedido?.emailConsumidor || ""),
  ].map(limparEmail));

  return { telefone: fones[0] || null, email: emails[0] || null };
}

function extrairPedidos(pages) {
  const out = [];
  for (const pagina of pages || []) {
    for (const pedido of (pagina?.content || [])) {
      const { telefone, email } = extrairContatoSimples(pedido);
      const nomeCliente = limparTexto(
        pedido?.nomeConsumidorOuCliente ||
        pedido?.cliente?.nome ||
        pedido?.nomeConsumidor ||
        pedido?.cliente?.fantasiaSobrenome ||
        "CONSUMIDOR"
      );

      // *** ADICIONADO: Captura do código do cliente ***
      const codigoCliente = pedido?.cliente?.codigoCliente || null;

      const vendedor = limparTexto(pedido?.nomeVendedor || "");
      const codigoVendedor = pedido?.codigoVendedor || null;
      const enderecoCliente = montarEnderecoCliente(pedido);

      const dataPedido =
        normalizaData(pedido?.dataUltimaAlteracao) ||
        normalizaData(pedido?.dataEntrega) ||
        normalizaData(pedido?.dataEntrada) ||
        normalizaData(pedido?.dataPrevisaoEntrega) ||
        normalizaData(pedido?.dataOrigem) ||
        null;

      for (const item of (pedido?.itens || [])) {
        const produto = limparTexto(item?.descricaoCompleta || item?.descricaoProduto || "");
        const quantidade = toNumber(item?.quantidade) ?? 1;
        const preco = toNumber(item?.totalItem) ?? 0;

        const dataItem =
          normalizaData(item?.dataFaturamento) ||
          normalizaData(item?.dataEntrada) ||
          dataPedido;

        out.push({
          numeroDocumento: String(pedido?.numeroDocumento || ""),
          codigoCliente, // *** ADICIONADO aqui ***
          nomeCliente,
          enderecoCliente,
          vendedor,
          codigoVendedor,
          produto,
          quantidade,
          preco,
          data: dataItem,
          telefone,
          email,
          codigoAtividade: pedido?.cliente?.codigoAtividade || null,
          nomeVendedor: vendedor || null
        });
      }
    }
  }
  return out;
}

