// Função para validar o telefone
function telefoneValido(fone) {
  if (!fone) return false;
  const digits = String(fone).replace(/\D/g, "");
  // deve ter 10 ou 11 dígitos
  if (!(digits.length === 10 || digits.length === 11)) return false;
  // ignora se todos os dígitos forem iguais (ex: 1111111111)
  if (/^(\d)\1+$/.test(digits)) return false;
  // ignora se número principal (sem DDD) for só de 9s (ex: 99999999 ou 999999999)
  const numeroPrincipal = digits.length === 11 ? digits.slice(2) : digits.slice(2);
  if (/^9{8,9}$/.test(numeroPrincipal)) return false;
  return true;
}

