function to2(n) { return Math.round((n + Number.EPSILON) * 100) / 100; }

function ensureArrayFromItems(items) {
  if (!items?.length) return [];
  const j0 = items[0].json;
  if (Array.isArray(j0)) return j0; // primeiro item é o array completo
  return items.map(i => i.json);    // caso comum: um pedido por item
}

function totalPedido(p) {
  return to2((p.produtos || []).reduce((acc, it) => acc + Number(it.preco || 0), 0));
}

function qtdItens(p) {
  return (p.produtos || []).reduce((acc, it) => acc + Number(it.quantidade || 0), 0);
}

function acum(map, key, valor) {
  if (!map[key]) map[key] = 0;
  map[key] += valor;
}

function topN(dict, n, by = 'valor') {
  const arr = Object.entries(dict).map(([k, v]) => {
    if (typeof v === 'number') return { nome: k, valor: v };
    return { nome: k, valor: v.valor ?? 0, qtd: v.qtd ?? 0 };
  });
  arr.sort((a, b) => (b[by] ?? 0) - (a[by] ?? 0));
  return arr.slice(0, n).map(x => ({ ...x, valor: to2(x.valor) }));
}

